module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);
    // TODO: Please implement multi-16bit module according to the description below.
    // -------------------------------------------------------------
    // -------------------      Description      -------------------
    // -------------------------------------------------------------
    // This module should implement an unsigned 16-bit multiplier
    // The operation is shift and accumulate
    // --- Inputs
    // clk:            The clock signal
    // rst_n:          The reset signal, active low
    // start:          The start control signal
    // ain[15:0]:      The multiplicand
    // bin[15:0]:      The multiplier
    // --- Outputs
    // yout[31:0]:     The product
    // done:           The done control signal
    // -------------------------------------------------------------
    // -------------------      Implementation     -----------------
    // -------------------------------------------------------------
    // ADD YOUR CODE HERE
    reg [4:0] i;
    reg done_r;
    reg [31:0] areg;
    reg [15:0] breg;
    reg [31:0] yout_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i <= 5'd0;
        end else if (start) begin
            if (i < 5'd17) begin
                i <= i + 1;
            end else begin
                i <= 5'd0;
            end
        end else begin
            i <= 5'd0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            done_r <= 1'b0;
        end else if (i == 5'd16) begin
            done_r <= 1'b1;
        end else if (i == 5'd17) begin
            done_r <= 1'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            areg <= 16'd0;
            breg <= 16'd0;
            yout_r <= 32'd0;
        end else if (start) begin
            if (i == 5'd0) begin
                areg <= ain;
                breg <= bin;
            end else if (i > 5'd0 && i < 5'd17) begin
                if (areg[i-1]) begin
                    yout_r <= yout_r + (breg << (i-1));
                end
            end
        end
    end
    assign done = done_r;
    assign yout = yout_r;
endmodule
